// // This module is designed to be a 4-bit counter that increments on each rising edge of the clock and resets to 0 on a high reset signal.
module counter(
   input  wire            clk,
   input  wire            reset,
   output reg  [3:0]      count
);

always @(posedge clk) begin
   if (reset) begin
      count <= 4'b0000;
   end else begin
      count <= count + 1;
   end
end

endmodule
